mapper.select:
select ts.id, ts.task_id, t.name as task_name, ts.user_id, u.real_name as user_name, ts.work_date, ts.hours, ts.cost_rate, ts.labor_cost, ts.description, ts.status from timesheet ts left join project_task t on t.id = ts.task_id left join sys_user u on u.id = ts.user_id where ts.project_id = #{projectId} and ts.is_deleted = 0
and ts.user_id = #{query.userId}
and ts.task_id = #{query.taskId}
and ts.work_date >= #{query.startDate}
and ts.work_date <= #{query.endDate}
order by ts.work_date desc, ts.created_at desc

mapper.insert:
insert into timesheet (
    id, project_id, task_id, user_id, work_date, hours, cost_rate, labor_cost, description, status,
    created_at, updated_at, is_deleted
) values (
    #{id}, #{projectId}, #{taskId}, #{userId}, #{workDate}, #{hours}, #{costRate}, #{laborCost}, #{description}, #{status},
    #{createdAt}, #{updatedAt}, #{deleted}
)

mapper.update:
update timesheet
set is_deleted = 1,
    updated_at = #{updatedAt}
where id = #{id}
  and is_deleted = 0

mapper.select:
select coalesce(sum(hours), 0)
from timesheet
where project_id = #{projectId}
  and task_id = #{taskId}
  and is_deleted = 0

select coalesce(sum(labor_cost), 0)
from timesheet
where project_id = #{projectId}
  and task_id = #{taskId}
  and is_deleted = 0
